<script setup lang="ts">import{Head,useForm}from'@inertiajs/vue3';import{LockKeyhole}from'@lucide/vue';import BrandLogo from '../../Components/BrandLogo.vue';const props=defineProps<{token:string,email:string}>();const form=useForm({token:props.token,email:props.email,password:'',password_confirmation:''});</script>
<template><Head title="Choose a new password"/><main class="simple-auth-page"><section><BrandLogo/><h1>Choose a new password</h1><p>Use at least eight characters with letters and numbers.</p><form @submit.prevent="form.post('/password/reset')"><label>Email address<input v-model="form.email" class="su-input" type="email" required/></label><label>New password<span class="auth-input-icon"><LockKeyhole/><input v-model="form.password" class="su-input" type="password" required/></span></label><label>Confirm password<span class="auth-input-icon"><LockKeyhole/><input v-model="form.password_confirmation" class="su-input" type="password" required/></span></label><small v-if="form.errors.email||form.errors.password" class="error">{{form.errors.email||form.errors.password}}</small><button class="su-btn su-btn-primary" :disabled="form.processing">{{form.processing?'Resetting…':'Reset password'}}</button></form></section></main></template>
